"""HLD Core Concepts: Networking Essentials, API Design, Data Modeling — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def networking_lesson() -> Lesson:
    return Lesson(id="hld-networking", number=100, title="Networking Essentials",
        focus=("TCP/UDP","HTTP/2","DNS","WebSockets","CDN","load balancing"),
        overview="Networking fundamentals that underpin every system design.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("net-1","What is the key difference between TCP and UDP?","medium",("networking",),("TCP is faster, UDP is slower","TCP guarantees delivery and ordering; UDP does not","UDP is encrypted, TCP is not","TCP is connectionless"),1,"TCP provides reliable, ordered delivery via handshakes. UDP sacrifices that for lower latency."),
        quiz("net-2","Why would you choose UDP over TCP for live video streaming?","medium",("networking",),("UDP is more secure","Lower latency — a few dropped frames beat head-of-line blocking","UDP handles larger payloads","UDP has built-in encryption"),1,"For real-time media, occasional packet loss is preferable to TCP's retransmission delays."),
        quiz("net-3","What does DNS resolve?","easy",("networking",),("IP to MAC addresses","Domain names to IP addresses","Ports to services","URLs to file paths"),1,"DNS maps human-readable domain names to IP addresses."),
        quiz("net-4","What is the primary role of a load balancer?","easy",("networking",),("Encrypt traffic","Distribute incoming traffic across multiple servers","Cache responses","Manage DNS"),1,"Load balancers prevent any single server from being overwhelmed."),
        quiz("net-5","What is the difference between L4 and L7 load balancing?","hard",("networking",),("L4 works at transport layer (TCP/UDP); L7 at application layer (HTTP)","L4 is slower","L7 cannot handle HTTPS","L4 inspects request body"),0,"L4 routes by IP/port; L7 makes decisions based on HTTP headers, paths, cookies."),
        quiz("net-6","When would you use WebSockets instead of HTTP polling?","medium",("networking",),("File uploads","Server needs to push data to clients in real-time with low latency","You need caching","Requests are infrequent"),1,"WebSockets maintain a persistent bidirectional connection for chat, live feeds, gaming."),
        quiz("net-7","What is Server-Sent Events (SSE) best suited for?","medium",("networking",),("Bidirectional communication","Unidirectional server-to-client streaming over HTTP","File downloads","Database replication"),1,"SSE is simpler than WebSockets for one-way server push like live scores and notifications."),
        quiz("net-8","What is the purpose of a CDN?","easy",("networking",),("Database replication","Serve static content from edge servers geographically closer to users","Load balance APIs","Encrypt traffic"),1,"CDNs cache and serve static assets from edge locations, reducing latency."),
        quiz("net-9","What does a reverse proxy do?","medium",("networking",),("Hides the client identity","Sits in front of servers and forwards client requests to backends","Replaces DNS","Encrypts DB connections"),1,"A reverse proxy provides load balancing, SSL termination, and caching."),
        quiz("net-10","What is the thundering herd problem?","hard",("networking",),("Too many indexes","A surge of requests hitting a service simultaneously after a cache miss or restart","DNS propagation delay","TCP timeout"),1,"Mitigated with jitter, circuit breakers, or request coalescing."),
        quiz("net-11","What is gRPC and when would you prefer it over REST?","hard",("networking",),("A text-based protocol","Uses Protocol Buffers over HTTP/2 for high-performance inter-service communication","Replaces WebSockets","Only for streaming"),1,"gRPC offers binary serialization, multiplexing, and streaming — ideal for internal microservice calls."),
        quiz("net-12","What problem does connection pooling solve?","medium",("networking",),("DNS latency","The overhead of repeatedly creating and destroying TCP connections","SSL certificates","LB failover"),1,"Connection pools reuse connections, avoiding TCP handshake and TLS negotiation costs."),
        quiz("net-13","What is service discovery in microservices?","medium",("networking",),("Finding bugs","A mechanism for services to find each other's network locations dynamically","A LB algorithm","A caching strategy"),1,"Service discovery (Consul, K8s DNS) allows services to locate each other without hardcoded addresses."),
        quiz("net-14","What is the TCP three-way handshake?","medium",("networking",),("GET→POST→PUT","SYN → SYN-ACK → ACK","CONNECT→ACCEPT→CLOSE","REQUEST→RESPONSE→CONFIRM"),1,"TCP connections begin with SYN from client, SYN-ACK from server, ACK from client."),
        quiz("net-15","Why is HTTP/2 preferred over HTTP/1.1?","hard",("networking",),("HTTP/2 uses XML","Multiplexing multiple requests over a single connection, header compression, server push","Simpler to implement","Doesn't need TLS"),1,"HTTP/2 eliminates head-of-line blocking at application layer with multiplexed streams."),
        quiz("net-16","What is a circuit breaker pattern?","hard",("networking",),("Hardware component","Stops calling a failing service after a threshold, preventing cascade failures","A load balancer","A DB isolation level"),1,"Circuit breakers trip after N failures, returning errors immediately instead of waiting on a dead service."),
        quiz("net-17","What is the difference between horizontal and vertical scaling?","easy",("networking",),("Horizontal is cheaper","Horizontal adds more machines; vertical upgrades existing machine resources","Vertical is always better","They are the same"),1,"Horizontal (scale out) adds nodes; vertical (scale up) adds CPU/RAM to one node."),
        quiz("net-18","What is anycast routing?","hard",("networking",),("Routing to all servers","Routing to the nearest server sharing the same IP, used by CDNs and DNS","A multicast alternative","A LB algorithm"),1,"Anycast routes traffic to the topologically nearest node. Used by Cloudflare and DNS root servers."),
        quiz("net-19","What is HTTP long polling?","medium",("networking",),("Client sends requests every second","Server holds the request open until new data is available, then responds","A WebSocket type","A caching technique"),1,"Long polling simulates server push: server delays response until new data, client re-requests immediately."),
        quiz("net-20","What is head-of-line blocking?","hard",("networking",),("A CDN issue","When a slow/lost packet blocks all subsequent packets in the same connection","A DNS problem","A firewall issue"),1,"In HTTP/1.1, one slow request blocks all others on the same connection. HTTP/2 multiplexing solves this."),
    ))

def api_design_lesson() -> Lesson:
    return Lesson(id="hld-api-design", number=101, title="API Design",
        focus=("REST","GraphQL","idempotency","pagination","versioning","rate limiting"),
        overview="API design is critical in interviews — define endpoints, choose protocols, handle edge cases.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("api-1","What makes an API call idempotent?","medium",("api",),("It always succeeds","Making the same call multiple times produces the same result as once","It returns faster","It uses caching"),1,"Idempotency ensures retries are safe. PUT/DELETE are naturally idempotent; POST isn't."),
        quiz("api-2","Which HTTP methods are idempotent?","medium",("api",),("Only GET","GET, PUT, DELETE","POST, PATCH","All methods"),1,"GET (safe), PUT, DELETE are idempotent. POST creates new resources each time."),
        quiz("api-3","When would you choose GraphQL over REST?","medium",("api",),("Maximum simplicity","Clients need flexible queries and want to avoid over/under-fetching","File uploads","Single client"),1,"GraphQL lets clients request exactly the fields they need."),
        quiz("api-4","What is the N+1 query problem?","hard",("api",),("N+1 API calls","Fetching a list (1 query) then fetching related data for each item (N queries)","Too many endpoints","N+1 HTTP methods"),1,"Solutions: batching, DataLoader pattern, or eager loading with JOINs."),
        quiz("api-5","What is an idempotency key?","hard",("api",),("A database primary key","A unique client-generated token to prevent duplicate processing on retries","An API version","A session token"),1,"Idempotency keys (e.g., Stripe's) let servers detect and deduplicate retried requests."),
        quiz("api-6","What is the difference between cursor-based and offset-based pagination?","hard",("api",),("They are identical","Offset skips N rows (fragile); cursor uses an opaque pointer (stable)","Cursor is slower","Offset is more accurate"),1,"Cursor pagination avoids the shifting window problem when data changes between pages."),
        quiz("api-7","What is the difference between PUT and PATCH?","medium",("api",),("No difference","PUT replaces the entire resource; PATCH applies a partial update","PATCH is faster","PUT is for creation only"),1,"PUT requires sending the full resource representation; PATCH sends only changed fields."),
        quiz("api-8","What HTTP status code indicates rate limiting?","medium",("api",),("500","429 Too Many Requests","403 Forbidden","503 Service Unavailable"),1,"429 tells the client to slow down. Usually includes a Retry-After header."),
        quiz("api-9","How should you version your API?","medium",("api",),("Never version","URL path (/v1/), query params, or Accept headers","Change domain","Use different ports"),1,"URL path versioning is most common. Header versioning is cleaner but less discoverable."),
        quiz("api-10","What is the purpose of HATEOAS?","hard",("api",),("Faster responses","Including links in responses so clients discover available actions dynamically","A caching mechanism","Error handling"),1,"HATEOAS makes APIs self-documenting by embedding navigation links."),
        quiz("api-11","When would you use webhooks?","medium",("api",),("Database queries","Server needs to notify external clients about events asynchronously","Authentication","File storage"),1,"Webhooks push event notifications to registered URLs — used by Stripe, GitHub, Slack."),
        quiz("api-12","What is the difference between sync and async API calls?","medium",("api",),("Sync is faster","Sync blocks until response; async returns 202 with a job ID for later polling","Async doesn't respond","Different HTTP methods"),1,"Async APIs return 202 Accepted with a job/task ID. Client polls or gets webhook callback."),
        quiz("api-13","What is an API gateway?","medium",("api",),("A database proxy","A single entry point handling routing, auth, rate limiting for microservices","A CDN","A message queue"),1,"API gateways centralize cross-cutting concerns and simplify client-to-microservice communication."),
        quiz("api-14","What is back-pressure in API design?","hard",("api",),("Compression","A mechanism where a service signals upstream it's overwhelmed and requests should slow down","A caching strategy","A load balancer"),1,"Back-pressure prevents cascade failures by propagating overload signals upstream."),
        quiz("api-15","What is content negotiation?","hard",("api",),("Negotiating API pricing","Using Accept/Content-Type headers to agree on response format (JSON, XML, Protobuf)","Rate limiting","Versioning"),1,"Content negotiation lets clients and servers agree on data format via HTTP headers."),
        quiz("api-16","Why shouldn't GET requests modify data?","medium",("api",),("GET is slower","GET can be cached, bookmarked, retried by browsers/proxies, causing unintended mutations","GET can't send JSON","GET has size limits"),1,"GET is defined as safe and idempotent — caches, crawlers, prefetchers may replay them."),
        quiz("api-17","What is the difference between authentication and authorization?","easy",("api",),("Same thing","Authentication verifies identity; authorization determines what the identity can access","AuthN is for APIs only","AuthZ comes first"),1,"AuthN (who are you?) comes before AuthZ (what are you allowed to do?)."),
        quiz("api-18","What is API rate limiting?","medium",("api",),("Speeds up responses","Restricts requests a client can make in a time window to prevent abuse","Encrypts traffic","Replaces auth"),1,"Rate limiting protects services from abuse and ensures fair usage."),
        quiz("api-19","What is the difference between REST and RPC style APIs?","medium",("api",),("No difference","REST is resource-oriented (nouns); RPC is action-oriented (verbs)","REST is faster","RPC doesn't use HTTP"),1,"REST: GET /users/123. RPC: getUser(123). REST models resources; RPC models operations."),
        quiz("api-20","What is a 201 status code?","easy",("api",),("OK","Created — successful resource creation via POST","No Content","Redirect"),1,"201 Created is the standard response for successful POST requests that create a resource."),
    ))

def data_modeling_lesson() -> Lesson:
    return Lesson(id="hld-data-modeling", number=102, title="Data Modeling",
        focus=("SQL vs NoSQL","normalization","denormalization","replication","OLTP/OLAP"),
        overview="Choosing the right data model and database is the backbone of every system design.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("dm-1","When would you choose NoSQL over relational?","medium",("data-modeling",),("Always, NoSQL is newer","Schema varies significantly and you need horizontal scalability","Strong ACID transactions","Highly relational data"),1,"Document stores excel at flexible schemas and horizontal scaling, but sacrifice JOINs."),
        quiz("dm-2","What is database normalization?","easy",("data-modeling",),("Making data bigger","Organizing data to reduce redundancy by splitting into related tables","Encrypting data","Indexing all columns"),1,"Normalization (1NF→2NF→3NF) eliminates data redundancy."),
        quiz("dm-3","When is denormalization the right choice?","medium",("data-modeling",),("Always in production","Read performance matters more than write consistency, and you tolerate duplication","Data is small","Using NoSQL"),1,"Denormalization precomputes JOINs, trading storage for read speed."),
        quiz("dm-4","What is the difference between horizontal and vertical partitioning?","medium",("data-modeling",),("Same thing","Horizontal splits rows across shards; vertical splits columns across tables","Horizontal is SQL only","Vertical adds replicas"),1,"Horizontal partitioning (sharding) distributes rows; vertical separates columns."),
        quiz("dm-5","What is database replication?","easy",("data-modeling",),("Moving data","Copying data across nodes for fault tolerance and read scalability","Daily backup","Encryption"),1,"Replication ensures availability if one node fails and distributes reads."),
        quiz("dm-6","What is the difference between leader-follower and multi-leader replication?","hard",("data-modeling",),("No difference","Leader-follower has one write node; multi-leader allows writes to multiple nodes","Multi-leader is slower","Leader-follower doesn't replicate"),1,"Multi-leader improves write availability but introduces write conflicts."),
        quiz("dm-7","What is eventual consistency?","medium",("data-modeling",),("Never consistent","All replicas converge to same state given enough time without new writes","Reads always return latest","A DB error state"),1,"Eventual consistency trades immediate consistency for availability (AP in CAP)."),
        quiz("dm-8","What is a write-ahead log (WAL)?","hard",("data-modeling",),("A backup schedule","Changes recorded before being applied, ensuring durability and crash recovery","A query optimizer","An index type"),1,"WAL ensures durability: if DB crashes after logging but before applying, it replays on restart."),
        quiz("dm-9","What is the difference between OLTP and OLAP?","medium",("data-modeling",),("Same thing","OLTP handles transactional workloads (many small writes); OLAP handles analytics (large aggregations)","OLAP is faster for writes","OLTP is for warehousing"),1,"OLTP: PostgreSQL. OLAP: BigQuery, Redshift, ClickHouse."),
        quiz("dm-10","What is the difference between strong consistency and linearizability?","hard",("data-modeling",),("Same thing","Strong ensures reads return latest write; linearizability adds real-time ordering guarantees","Linearizability is weaker","Strong is SQL only"),1,"Linearizability is the strongest: operations appear atomic at some point between invocation and response."),
        quiz("dm-11","What is a materialized view?","medium",("data-modeling",),("A regular view","A precomputed query result stored as table, periodically refreshed","A type of index","A cache layer"),1,"Materialized views precompute expensive JOINs/aggregations. Great for dashboards."),
        quiz("dm-12","What is a tombstone in distributed databases?","hard",("data-modeling",),("A crashed server","A marker for deleted records, propagating deletions across replicas before compaction","A backup mechanism","An index entry"),1,"Tombstones prevent deleted data from being resurrected by replicas."),
        quiz("dm-13","What is optimistic vs pessimistic locking?","hard",("data-modeling",),("No difference","Optimistic assumes no conflict and checks at commit; pessimistic locks upfront","Optimistic is always better","Pessimistic doesn't use locks"),1,"Optimistic (version numbers) for low contention. Pessimistic (SELECT FOR UPDATE) prevents conflicts."),
        quiz("dm-14","What is a wide-column store?","hard",("data-modeling",),("A SQL table with many columns","A NoSQL store where rows can have different columns, organized by partition+clustering keys","A document store","A graph database"),1,"Cassandra/HBase: data organized by partition key, columns can vary per row. Ideal for write-heavy workloads."),
        quiz("dm-15","What is the difference between a document store and a key-value store?","medium",("data-modeling",),("Same thing","Document stores understand document structure (query by fields); KV stores treat values as opaque blobs","KV is newer","Document stores don't support queries"),1,"MongoDB (document) lets you query by nested fields. Redis/DynamoDB (KV) primarily support key lookup."),
        quiz("dm-16","What is a graph database best suited for?","medium",("data-modeling",),("Time series data","Highly connected data with complex relationship traversals (social networks, recommendations)","Simple key-value lookups","Flat tabular data"),1,"Graph DBs (Neo4j) excel at traversing relationships — friend-of-friend queries in O(k) per hop."),
        quiz("dm-17","What is the difference between row-oriented and column-oriented storage?","hard",("data-modeling",),("Same thing","Row stores data row-by-row (good for OLTP); column stores data column-by-column (good for analytics)","Row is always faster","Column can't handle aggregations"),1,"Column stores (Parquet, ClickHouse) compress better and scan only needed columns for analytics."),
        quiz("dm-18","What is data partitioning by range vs hash?","medium",("data-modeling",),("Same thing","Range assigns key ranges to partitions (range scans); hash assigns by hash (even distribution)","Hash is always better","Range doesn't work with strings"),1,"Range supports range queries but risks hotspots. Hash distributes evenly but loses range capability."),
        quiz("dm-19","What is multi-tenancy in database design?","medium",("data-modeling",),("Multiple databases","Multiple customers share the same DB/tables, isolated by tenant_id column or schema","One customer per server","A replication strategy"),1,"Multi-tenancy options: shared DB + tenant column, separate schemas, or separate databases."),
        quiz("dm-20","What is a time-series database optimized for?","medium",("data-modeling",),("User profiles","Append-heavy workloads with timestamp-ordered data like metrics, IoT, financial data","Graph traversals","Full-text search"),1,"Time-series DBs (InfluxDB, TimescaleDB) optimize for high write throughput and time-range queries."),
    ))
